function validate(args, output) {
    const [nums, indexDifference, valueDifference] = args;
    const n = nums.length;
    if (!Array.isArray(output) || output.length !== 2) return false;
    const [i, j] = output;
    if (!Number.isInteger(i) || !Number.isInteger(j)) return false;
    if (i === -1 && j === -1) {
        function existsValidPair() {
            let minIdx = 0, maxIdx = 0;
            for (let idx = indexDifference; idx < n; idx++) {
                const p = idx - indexDifference;
                if (nums[p] < nums[minIdx]) minIdx = p;
                if (nums[p] > nums[maxIdx]) maxIdx = p;
                if (nums[idx] - nums[minIdx] >= valueDifference) return true;
                if (nums[maxIdx] - nums[idx] >= valueDifference) return true;
            }
            return false;
        }
        return !existsValidPair();
    }
    if (!(i >= 0 && i < n && j >= 0 && j < n)) return false;
    if (Math.abs(i - j) < indexDifference) return false;
    if (Math.abs(nums[i] - nums[j]) < valueDifference) return false;
    return true;
}

