class Solution:
    def findIndices(self, nums, indexDifference, valueDifference):
        n = len(nums)
        for i in range(indexDifference, n):
            window = nums[0:i - indexDifference + 1]
            lo = min(window)
            hi = max(window)
            lo_idx = window.index(lo)
            hi_idx = window.index(hi)
            if nums[i] - lo >= valueDifference:
                return [lo_idx, i]
            if hi - nums[i] >= valueDifference:
                return [hi_idx, i]
        return [-1, -1]

